<?php
require_once '../includes/helpers.php';
require_login(); csrf_check();
if ($_SERVER['REQUEST_METHOD']==='POST') {
    db()->prepare('INSERT INTO sales (breeder_id,puppy_id,buyer_name,buyer_firstname,buyer_address,buyer_company,sale_date,delivery_date,price,payment_method,documents_given,guarantees,invoice_number) VALUES (:bid,:puppy,:bn,:bf,:addr,:company,:sale,:delivery,:price,:pay,:docs,:guar,:invoice)')->execute(['bid'=>breeder_id(),'puppy'=>post_value('puppy_id') ?: null,'bn'=>post_value('buyer_name'),'bf'=>post_value('buyer_firstname'),'addr'=>post_value('buyer_address'),'company'=>post_value('buyer_company'),'sale'=>post_value('sale_date') ?: null,'delivery'=>post_value('delivery_date') ?: null,'price'=>post_value('price') ?: null,'pay'=>post_value('payment_method'),'docs'=>post_value('documents_given'),'guar'=>post_value('guarantees'),'invoice'=>post_value('invoice_number')]);
    if(post_value('puppy_id')) db()->prepare('UPDATE puppies SET is_sold=true,status=:s,owner_name=:n,owner_firstname=:f,owner_address=:a WHERE id=:id AND breeder_id=:bid')->execute(['s'=>'vendu','n'=>post_value('buyer_name'),'f'=>post_value('buyer_firstname'),'a'=>post_value('buyer_address'),'id'=>post_value('puppy_id'),'bid'=>breeder_id()]);
    $_SESSION['flash']='Vente enregistrée.'; redirect('/sales.php');
}
$puppies=db()->prepare("SELECT id,name FROM puppies WHERE breeder_id=:bid AND COALESCE(is_sold,false)=false ORDER BY name");$puppies->execute(['bid'=>breeder_id()]);
$rows=db()->prepare('SELECT s.*, p.name puppy FROM sales s LEFT JOIN puppies p ON p.id=s.puppy_id WHERE s.breeder_id=:bid ORDER BY s.created_at DESC');$rows->execute(['bid'=>breeder_id()]);
render_header('Ventes'); flash();
?>
<div class="card"><h2>Nouvelle vente</h2><form method="post"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-grid"><label>Chiot<select name="puppy_id"><option value="">—</option><?php foreach($puppies as $p): ?><option value="<?= (int)$p['id'] ?>"><?= e($p['name']) ?></option><?php endforeach; ?></select></label><label>Nom acheteur<input name="buyer_name"></label><label>Prénom<input name="buyer_firstname"></label><label>Société<input name="buyer_company"></label><label>Date vente<input type="date" name="sale_date"></label><label>Date livraison<input type="date" name="delivery_date"></label><label>Prix<input type="number" step="0.01" name="price"></label><label>Paiement<input name="payment_method"></label><label>Facture<input name="invoice_number"></label></div><label>Adresse<textarea name="buyer_address"></textarea></label><label>Documents remis<textarea name="documents_given"></textarea></label><label>Garanties<textarea name="guarantees"></textarea></label><button class="btn">Enregistrer</button></form></div>
<div class="card" style="margin-top:16px"><table><tr><th>Facture</th><th>Chiot</th><th>Acheteur</th><th>Date</th><th>Prix</th><th>Paiement</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['invoice_number']) ?></td><td><?= e($r['puppy']) ?></td><td><?= e(trim($r['buyer_firstname'].' '.$r['buyer_name'])) ?></td><td><?= e($r['sale_date']) ?></td><td><?= e($r['price']) ?></td><td><?= e($r['payment_method']) ?></td></tr><?php endforeach; ?></table></div>
<?php render_footer(); ?>
